mapper.select:
select

from book b
inner join publisher p on b.publisher_id = p.id
where lower(b.title) like concat('%', lower(#{keyword,jdbcType=VARCHAR}), '%')

  and b.release_date between #{releaseDateFrom,jdbcType=DATE} and #{releaseDateTo,jdbcType=DATE}

order by b.id
limit #{limit,jdbcType=INTEGER}
offset #{offset,jdbcType=BIGINT}
